async (page) => {
  const result = await page.evaluate((id) => window.__talkToNPC(id), '1-7924149');
  await page.waitForTimeout(2000);
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  return JSON.stringify({pos: parsed.player_position, npc_dialogue: parsed.ui_state.npc_dialogue, quest_panel: parsed.ui_state.quest_panel_visible, quests: parsed.quests, result});
}
